export declare const code = "// Track mouse position relative to card, map to rotateX/Y\nfunction onMouseMove(e: MouseEvent) {\n  const { left, top, width, height } = card.getBoundingClientRect();\n  const x = (e.clientX - left) / width  - 0.5;  // -0.5 \u2192 +0.5\n  const y = (e.clientY - top)  / height - 0.5;\n\n  card.style.transform =\n    `rotateY(${x * 28}deg) rotateX(${-y * 28}deg) scale(1.04)`;\n  \n  // Move a radial-gradient highlight with the cursor\n  card.style.setProperty('--mx', `${(x + 0.5) * 100}%`);\n  card.style.setProperty('--my', `${(y + 0.5) * 100}%`);\n}";
export default function G4PerspectiveTilt(): import("react/jsx-runtime").JSX.Element;
